import React, { useState, useEffect } from "react";
import "./InternshipModal.css";

export default function InternshipModal({ show, onClose, onSave, internship }) {
  const [form, setForm] = useState({
    title: "",
    company: "",
    category: "",
    location: "",
    mode: "",
    duration: "",
    stipend: ""
  });

  useEffect(() => {
    if (internship) setForm(internship);
  }, [internship]);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = () => {
    onSave(form);
    onClose();
  };

  if (!show) return null;

  return (
    <div className="modal-backdrop">
      <div className="modal">
        <h2>{internship ? "Edit" : "Add"} Internship</h2>
        {Object.keys(form).map((key) => (
          <input key={key} name={key} placeholder={key} value={form[key]} onChange={handleChange} />
        ))}
        <button onClick={handleSubmit}>Save</button>
        <button onClick={onClose}>Cancel</button>
      </div>
    </div>
  );
}
